#' Recursive Partitioning Analysis for Survival
#'
#' Recursive Partitioning Analysis (RPA) for survival data using CART 
#' methodology. Builds a decision tree to identify optimal cut-points for risk 
#' stratification. Automatically performs cross-validation and tree pruning. 
#' Creates new variable with risk group assignments. Useful for developing 
#' prognostic staging systems by integrating multiple predictors.
#'
#' @examples
#' \donttest{
#' # Example: Develop RPA staging system for survival data
#' # Generate example survival data with multiple predictors
#' set.seed(12345)
#' n <- 200
#'
#' survData <- data.frame(
#'     time = rexp(n, rate = 0.02),
#'     event = rbinom(n, 1, 0.65),
#'     age = rnorm(n, 60, 15),
#'     stage = factor(sample(c("I", "II", "III", "IV"), n, replace = TRUE,
#'                          prob = c(0.3, 0.3, 0.25, 0.15))),
#'     grade = factor(sample(c("G1", "G2", "G3"), n, replace = TRUE,
#'                          prob = c(0.2, 0.5, 0.3))),
#'     LVI = factor(sample(c("Absent", "Present"), n, replace = TRUE,
#'                        prob = c(0.6, 0.4)))
#' )
#'
#' # Basic RPA analysis
#' rpasurvival(
#'     data = survData,
#'     time = "time",
#'     event = "event",
#'     predictors = c("age", "stage", "grade", "LVI"),
#'     eventValue = "1",
#'     time_unit = "months",
#'     minbucket = 20,
#'     cp = 0.01,
#'     maxdepth = 3,
#'     prunetree = TRUE,
#'     treeplot = TRUE,
#'     kmplot = TRUE,
#'     riskgrouptable = TRUE,
#'     variableimportance = TRUE,
#'     riskgrouplabels = "auto",
#'     showSummary = TRUE,
#'     showReport = TRUE
#' )
#'
#' # Create and save risk groups as new variable
#' rpasurvival(
#'     data = survData,
#'     time = "time",
#'     event = "event",
#'     predictors = c("stage", "LVI"),
#'     createnewvar = TRUE,
#'     newvarname = "rpa_risk_group",
#'     riskgrouplabels = "risk"
#' )
#'
#' # Conservative settings for external validation
#' rpasurvival(
#'     data = survData,
#'     time = "time",
#'     event = "event",
#'     predictors = c("age", "stage", "grade"),
#'     minbucket = 30,      # Larger minimum node size
#'     cp = 0.02,           # More conservative pruning
#'     maxdepth = 2,        # Simpler tree
#'     nfolds = 10,         # 10-fold cross-validation
#'     prunetree = TRUE,
#'     cptable = TRUE       # Show complexity parameter table
#' )
#'}
#' @param data .
#' @param time a (non-negative valued) vector of survival times containing the
#'   (possibly censored) time to the event or time of last observation
#' @param event the status indicator; normally 0=alive/censored, 1=dead/event.
#'   Other choices are TRUE/FALSE (TRUE = death/event) or 1/2 (2=death/event)
#' @param predictors variables to use in recursive partitioning analysis for
#'   developing risk stratification groups
#' @param eventValue the value in the event variable that represents an event
#'   (death/failure)
#' @param time_unit unit of measurement for survival time. Used for
#'   calculating 5-year survival estimates in the risk group summary table.
#' @param minbucket the minimum number of observations in any terminal (leaf)
#'   node. Smaller values create more detailed trees but may overfit.
#' @param cp any split that does not decrease overall lack of fit by a factor
#'   of cp is not attempted. Smaller values grow larger trees.
#' @param maxdepth maximum depth of any node of the final tree, with the root
#'   node counted as depth 0. Values greater than 30 are unlikely.
#' @param nfolds number of cross-validation folds for pruning the tree. Use 0
#'   to suppress cross-validation.
#' @param prunetree prune the tree using cross-validation to select optimal
#'   complexity parameter
#' @param riskgrouplabels labeling scheme for terminal nodes (risk groups)
#' @param treeplot .
#' @param kmplot .
#' @param kmci .
#' @param risktable .
#' @param pval .
#' @param riskgrouptable .
#' @param cptable .
#' @param variableimportance .
#' @param createnewvar .
#' @param newvarname name for the new variable containing RPA stage
#'   assignments
#' @param showSummary .
#' @param showInterpretation .
#' @param showReport .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$instructions} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$summary} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$interpretation} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$report} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$treeplot} \tab \tab \tab \tab \tab Decision tree showing recursive partitioning splits for survival risk stratification \cr
#'   \code{results$riskgrouptable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$kmplot} \tab \tab \tab \tab \tab Kaplan-Meier survival curves stratified by RPA-derived risk groups \cr
#'   \code{results$logranktest} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$cptable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$varimp} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxmodel} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$riskgrouptable$asDF}
#'
#' \code{as.data.frame(results$riskgrouptable)}
#'
#' @export
rpasurvival <- function(
    data,
    time,
    event,
    predictors,
    eventValue = "1",
    time_unit = "months",
    minbucket = 20,
    cp = 0.01,
    maxdepth = 3,
    nfolds = 10,
    prunetree = TRUE,
    riskgrouplabels = "auto",
    treeplot = TRUE,
    kmplot = TRUE,
    kmci = FALSE,
    risktable = TRUE,
    pval = TRUE,
    riskgrouptable = TRUE,
    cptable = FALSE,
    variableimportance = TRUE,
    createnewvar = FALSE,
    newvarname = "rpa_stage",
    showSummary = TRUE,
    showInterpretation = FALSE,
    showReport = TRUE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("rpasurvival requires jmvcore to be installed (restart may be required)")

    if ( ! missing(time)) time <- jmvcore::resolveQuo(jmvcore::enquo(time))
    if ( ! missing(event)) event <- jmvcore::resolveQuo(jmvcore::enquo(event))
    if ( ! missing(predictors)) predictors <- jmvcore::resolveQuo(jmvcore::enquo(predictors))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(time), time, NULL),
            `if`( ! missing(event), event, NULL),
            `if`( ! missing(predictors), predictors, NULL))

    for (v in event) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- rpasurvivalOptions$new(
        time = time,
        event = event,
        predictors = predictors,
        eventValue = eventValue,
        time_unit = time_unit,
        minbucket = minbucket,
        cp = cp,
        maxdepth = maxdepth,
        nfolds = nfolds,
        prunetree = prunetree,
        riskgrouplabels = riskgrouplabels,
        treeplot = treeplot,
        kmplot = kmplot,
        kmci = kmci,
        risktable = risktable,
        pval = pval,
        riskgrouptable = riskgrouptable,
        cptable = cptable,
        variableimportance = variableimportance,
        createnewvar = createnewvar,
        newvarname = newvarname,
        showSummary = showSummary,
        showInterpretation = showInterpretation,
        showReport = showReport)

    analysis <- rpasurvivalClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

